-- ============================================================
-- GIMS 룩업 테이블 DDL + 실제 데이터
-- TC_GD000002: 공통코드 (용도/상세용도 등)
-- TC_GD000100: 법정동코드 → 주소 변환
--
-- I3(JejuFacilityLoadStep)에서 코드→명칭 변환에 사용
-- 레거시 select_rgetstgms01 JOIN 로직 재현용
-- 데이터 출처: 표준화 DB 실데이터 (2026-04-13 추출)
-- ============================================================

-- ── TC_GD000002 (공통코드) ──
-- 표준화 컬럼명 사용
CREATE TABLE TC_GD000002 (
    SN                  NUMBER(22)     NOT NULL,
    UGWTR_COM_CD        CHAR(50)       NOT NULL,
    CD_CN               VARCHAR2(500),
    REG_DT              DATE           NOT NULL,
    MDFCN_DT            DATE,
    GROUP_CD_SN         VARCHAR2(20)   NOT NULL,
    DEL_YMD             VARCHAR2(8),
    USE_YN              CHAR(1),
    ANNLS_USE_YN        CHAR(1),
    CD_ABBR             VARCHAR2(100),
    SORT_NO             NUMBER(22),
    RGTR                VARCHAR2(50),
    CONSTRAINT PK_TC_GD000002 PRIMARY KEY (SN)
);

COMMENT ON TABLE  TC_GD000002              IS '공통코드';
COMMENT ON COLUMN TC_GD000002.SN           IS '일련번호 (PK)';
COMMENT ON COLUMN TC_GD000002.UGWTR_COM_CD IS '지하수공통코드';
COMMENT ON COLUMN TC_GD000002.CD_CN        IS '코드내용 (명칭)';
COMMENT ON COLUMN TC_GD000002.REG_DT       IS '생성일시 (연월일시분초)';
COMMENT ON COLUMN TC_GD000002.MDFCN_DT     IS '변경일시 (연월일시분초)';
COMMENT ON COLUMN TC_GD000002.GROUP_CD_SN  IS '지하수공통그룹코드 (NGW_0003=용도, NGW_0013=상세용도)';
COMMENT ON COLUMN TC_GD000002.DEL_YMD      IS '삭제일자 (YYYYMMDD)';
COMMENT ON COLUMN TC_GD000002.USE_YN       IS '사용여부 (Y/N)';
COMMENT ON COLUMN TC_GD000002.ANNLS_USE_YN IS '연보사용여부 (Y/N)';
COMMENT ON COLUMN TC_GD000002.CD_ABBR      IS '코드약어';
COMMENT ON COLUMN TC_GD000002.SORT_NO      IS '정렬번호';
COMMENT ON COLUMN TC_GD000002.RGTR         IS '등록자';

-- ── TC_GD000100 (공통법정동코드) ──
-- 표준화 컬럼명 사용
CREATE TABLE TC_GD000100 (
    SN              NUMBER(22)     NOT NULL,
    STDG_CD         VARCHAR2(10)   NOT NULL,
    CTPV_NM         VARCHAR2(40)   NOT NULL,
    SGG_NM          VARCHAR2(30),
    EMD_NM          VARCHAR2(30),
    LI_NM           VARCHAR2(40),
    SORT_NO         NUMBER(22),
    CRT_YMD         VARCHAR2(8),
    DEL_YMD         VARCHAR2(8),
    LCLGV_CD        VARCHAR2(7),
    CTPV_ENG_NM     VARCHAR2(100),
    SGG_ENG_NM      VARCHAR2(30),
    EMD_ENG_NM      VARCHAR2(100),
    LI_ENG_NM       VARCHAR2(100),
    CONSTRAINT PK_TC_GD000100 PRIMARY KEY (SN)
);

CREATE UNIQUE INDEX UQ_TC_GD000100_STDG ON TC_GD000100(STDG_CD);

COMMENT ON TABLE  TC_GD000100              IS '공통법정동코드';
COMMENT ON COLUMN TC_GD000100.SN           IS '일련번호 (PK)';
COMMENT ON COLUMN TC_GD000100.STDG_CD      IS '법정동코드 (10자리)';
COMMENT ON COLUMN TC_GD000100.CTPV_NM      IS '시도명';
COMMENT ON COLUMN TC_GD000100.SGG_NM       IS '시군구명';
COMMENT ON COLUMN TC_GD000100.EMD_NM       IS '읍면동명';
COMMENT ON COLUMN TC_GD000100.LI_NM        IS '리명';
COMMENT ON COLUMN TC_GD000100.SORT_NO      IS '정렬번호';
COMMENT ON COLUMN TC_GD000100.CRT_YMD      IS '생성일자 (YYYYMMDD)';
COMMENT ON COLUMN TC_GD000100.DEL_YMD      IS '삭제일자 (YYYYMMDD)';
COMMENT ON COLUMN TC_GD000100.LCLGV_CD     IS '자치단체코드 (7자리)';
COMMENT ON COLUMN TC_GD000100.CTPV_ENG_NM  IS '시도영문명';
COMMENT ON COLUMN TC_GD000100.SGG_ENG_NM   IS '시군구영문명';
COMMENT ON COLUMN TC_GD000100.EMD_ENG_NM   IS '읍면동영문명';
COMMENT ON COLUMN TC_GD000100.LI_ENG_NM    IS '리영문명';


-- ============================================================
-- TC_GD000002 데이터 — NGW_0003 (지하수용도, 4건)
-- 레거시 매칭: SUBSTR(UGWTR_COM_CD, 2, 2) = IF.UWATER_SRV_CODE
--   '01' → SUBSTR='1', '02' → '2', '03' → '3', '04' → '4'
-- ============================================================

-- ============================================================
-- TC_GD000002 데이터 — NGW_0013 (지하수상세용도, 35건)
-- 레거시 매칭: UGWTR_COM_CD = IF.UWATER_DTL_SRV_CODE (직접매칭)
-- ============================================================

-- ============================================================
-- TC_GD000100 데이터 — 제주 법정동 (218건)
-- 레거시 매칭: IF.REGN_CODE = TC_GD000100.STDG_CD
-- ============================================================

COMMIT;
